scwin.f_Retrieve = async function (e) {
  if (ed_srchWrkStDt.getValue() == "" || ed_srchWrkEndDt.getValue() == "") {
    await $c.win.alert($p, "필수입력사항을 입력해주세요.");
    return;
  }
  if (co_lc_logisticsBranch.getValue() == "" && ed_srchVehclNo.getValue() == "") {
    await $c.win.alert($p, "전체로 조회시에는 차량번호는 필수입력사항입니다.");
    return;
  }
  $c.sbm.execute($p, sbm_retrieve);
};
