  ed_srchWrkEndDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
  ed_clntNo.setValue("");
  ed_clntNm.setValue("");
  ed_copCoClntNo.setValue("");
  ed_copCoClntNm.setValue("");
  ed_srchEqCd.setValue("");
  ed_srchVehclNo.setValue("");
  co_lc_logisticsBranch.setSelectedIndex(0);
