scwin.f_gridSumTextDisplay = function () {
  ds_oderCondition_sum.removeAll();
  ds_oderCondition_sum.setJSON(ds_oderCondition.getAllJSON());
  var clntNm = '';
  var sellAmt = 0,
    pchsAmt = 0,
    wrkQty = 0,
    wrkWt = 0,
    wrkCubic = 0;
  var totalProfit = 0,
    totSellAmt = 0,
    totPchsAmt = 0,
    totWrkQty = 0,
    totWrkWt = 0,
    totWrkCubic = 0;
  var chkVal = ds_oderCondition_sum.getCellData(0, "clntNm");
  var sumData = [];
  if (ds_oderCondition_sum.getRowCount() != 0) {
    for (var i = 0; i < ds_oderCondition_sum.getRowCount(); i++) {
      clntNm = ds_oderCondition_sum.getCellData(i, "clntNm");
      if (i != 0 && chkVal != clntNm) {
        totalProfit = sellAmt == 0 ? 0 : Math.trunc(pchsAmt / sellAmt * 100 * 1000) / 1000;
        sumData.push({
          clntNm: chb_subtotal.getValue() == '1' ? chkVal : '소 계',
          wrkQty: wrkQty,
          wrkWt: wrkWt,
          wrkCubic: wrkCubic,
          pchsAmt: pchsAmt,
          sellAmt: sellAmt,
          totalProfit: totalProfit == 0 ? '' : totalProfit,
          isSum: true,
          idx: i
        });
        chkVal = clntNm;
        wrkQty = 0;
        wrkWt = 0;
        wrkCubic = 0;
        pchsAmt = 0;
        sellAmt = 0;
        totalProfit = 0;
      }
      wrkQty += Number(ds_oderCondition_sum.getCellData(i, "wrkQty"));
      wrkWt += Number(ds_oderCondition_sum.getCellData(i, "wrkWt"));
      wrkCubic += Number(ds_oderCondition_sum.getCellData(i, "wrkCubic"));
      pchsAmt += Number(ds_oderCondition_sum.getCellData(i, "pchsAmt"));
      sellAmt += Number(ds_oderCondition_sum.getCellData(i, "sellAmt"));
      totWrkQty += Number(ds_oderCondition_sum.getCellData(i, "wrkQty"));
      totWrkWt += Number(ds_oderCondition_sum.getCellData(i, "wrkWt"));
      totWrkCubic += Number(ds_oderCondition_sum.getCellData(i, "wrkCubic"));
      totSellAmt += Number(ds_oderCondition_sum.getCellData(i, "sellAmt"));
      totPchsAmt += Number(ds_oderCondition_sum.getCellData(i, "pchsAmt"));
    }
    totalProfit = sellAmt == 0 ? 0 : Math.trunc(pchsAmt / sellAmt * 100 * 1000) / 1000;
    sumData.push({
      clntNm: chb_subtotal.getValue() == '1' ? chkVal : '소 계',
      wrkQty: wrkQty,
      wrkWt: wrkWt,
      wrkCubic: wrkCubic,
      pchsAmt: pchsAmt,
      sellAmt: sellAmt,
      totalProfit: totalProfit == 0 ? '' : totalProfit,
      isSum: true,
      idx: ds_oderCondition.getRowCount()
    });

    // 소계 스타일 적용
    if (chb_subtotal.getValue() == '1') {
      ds_oderCondition_sum.removeAll();
      ds_oderCondition_sum.setJSON(sumData);
    } else {
      for (var i = sumData.length - 1; i > -1; i--) {
        var idx = sumData[i].idx;
        ds_oderCondition_sum.insertJSON(idx, [sumData[i]]);
        for (var j = 0; j < gr_oderCondition.getColumnCount(); j++) {
          if (j == 0) {
            gr_oderCondition.setCellClass(idx, j, 'gridSubtotalDefault excelSubtotalLeft');
          } else {
            gr_oderCondition.setCellClass(idx, j, 'gridSubtotalDefault excelSubtotalRight');
          }
        }
      }
    }
  }

  // 전체 합계 (totalProfit);
  totalProfit = totSellAmt == 0 ? 0 : Math.trunc(totPchsAmt / totSellAmt * 100 * 1000) / 1000;
  gr_oderCondition.setFooterValue("f_selfVehclNo", ds_oderCondition.getRowCount());
  gr_oderCondition.setFooterValue("f_wrkQty", totWrkQty);
  gr_oderCondition.setFooterValue("f_wrkWt", totWrkWt);
  gr_oderCondition.setFooterValue("f_wrkCubic", totWrkCubic);
  gr_oderCondition.setFooterValue("f_pchsAmt", totPchsAmt);
  gr_oderCondition.setFooterValue("f_sellAmt", totSellAmt);
  gr_oderCondition.setFooterValue("f_totalProfit", totalProfit == 0 ? '' : totalProfit);
};
scwin.excel = async function () {
  var totCnt = ds_oderCondition_sum.getRowCount();
  var sheetTitle = "차량별운송실적조회";
  if (totCnt != 0) {
    cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      $c.data.downloadGridViewExcel($p, gr_oderCondition, {
        fileName: sheetTitle + ".xlsx",
        sheetName: sheetTitle
      });
    }
  } else {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
  }
};

//-------------------------------------------------------------------------
// Data Collection Event
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {
  ed_totalCnt.setValue(ds_oderCondition.getRowCount());
  if (ds_oderCondition.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003, new Array("조회결과"));
  } else {
    for (var i = 0; i < ds_oderCondition.getRowCount(); i++) {
      ds_oderCondition.setCellData(i, 'dptDt', ds_oderCondition.getCellData(i, 'dptDt').substring(0, 8));
      ds_oderCondition.setCellData(i, 'sort', i);
    }
  }
  scwin.f_gridSumTextDisplay();
};

