scwin.gr_oderCondition_onbeforesort = function (sortInfo) {
  console.log(sortInfo);
  for (var i = ds_oderCondition_sum.getRowCount() - 1; i > -1; i--) {
    if (ds_oderCondition_sum.getCellData(i, "isSum") == true) {
      ds_oderCondition_sum.removeRow(i);
    }
  }
  ds_oderCondition._sortInfo = sortInfo;
};

